}

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateThumbnail = async (title: string, headshotBase64: string): Promise<string> => {
  try {
    const model = 'gemini-2.5-flash-image';

    // Clean base64 string
    const base64Data = headshotBase64.split(',')[1] || headshotBase64;

    const prompt = `
      Create a professional, scroll-stopping YouTube Shorts vertical thumbnail (9:16 aspect ratio, 1080x1920).

      TITLE TO INCLUDE: "${title}"

      MAIN SUBJECT: Use the person from the provided headshot photo.

      DESIGN REQUIREMENTS:
      1. Place the YouTuber's headshot prominently.
      2. Match the person's facial expression to the tone of the title "${title}". 
      3. Use bold, vibrant, eye-catching 3D typography for the title text.
      4. High contrast, vibrant colors (electric blues, hot pinks, or fiery oranges).
      5. Cinematic rim lighting and glowing highlights around the subject.
      6. Shallow depth of field (blurry background related to the title's topic).
      7. Modern, dynamic text placement to maximize click-through rate.
      8. The final output must be high resolution, looking like a top-tier MrBeast or lifestyle creator thumbnail but in vertical format.

      Ensure the text is legible and has high impact.
    `;

    const response = await ai.models.generateContent({
      model: model,
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Data,
              mimeType: 'image/jpeg',
            },
          },
          {
            text: prompt,
          },
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: "9:16",
        },
      },
    });

    let imageUrl = '';
    const candidates = response.candidates;
    if (candidates && candidates.length > 0) {
      for (const part of candidates[0].content.parts) {
        if (part.inlineData) {
          imageUrl = `data:image/png;base64,${part.inlineData.data}`;
          break;
        }
      }
    }

    if (!imageUrl) {
      throw new Error("No image was generated by the model.");
    }

    return imageUrl;
  } catch (error) {
    console.error("Gemini Service Error:", error);
    throw error;
  }
};

